package com.cognizant.oauth.config;import org.springframework.context.annotation.*;import org.springframework.security.config.Customizer;import org.springframework.security.config.annotation.web.builders.HttpSecurity;import org.springframework.security.web.SecurityFilterChain;@Configuration public class SecurityConfig{@Bean SecurityFilterChain chain(HttpSecurity h)throws Exception{return h.authorizeHttpRequests(a->a.requestMatchers("/", "/actuator/health").permitAll().anyRequest().authenticated()).oauth2Login(Customizer.withDefaults()).build();}}
